const mid = msg.machine_id || msg.topic;
const host = msg.host;
const community = msg.community;
const port = msg.snmp_port;

const snmp = global.get('snmp');
if (!snmp) return null;

const msgId = mid + '_' + Date.now();
const walkers = ['cpu', 'storage', 'network', 'temp', 'ldi'];

const nodeRef = node;
walkers.forEach((walker, index) => {
    setTimeout(() => {
        let m = {
            machine_id: mid,
            topic: mid,
            _walker: walker,
            _msgid: msgId,
            payload: '',
            host: host,
            community: community,
            snmp_port: port,
            parts: { id: msgId, index: index, count: 5 }
        };
        let out = [null, null, null, null, null];
        out[index] = m;
        nodeRef.send(out);
    }, index * 400);
});
return null;

const snmp = global.get('snmp');
if (!snmp) { msg.payload = { cpu: null }; return msg; }

const targetOIDs = [
    { oid: '1.3.6.1.2.1.25.3.3.1.2', type: 'server' },
    { oid: '1.3.6.1.4.1.2636.3.1.13.1', type: 'juniper' }
];

const session = snmp.createSession(
    msg.host, msg.community || env.get('SNMP_COMMUNITY') || 'public',
    { port: msg.snmp_port || 161, version: snmp.Version2c, retries: 1, timeout: 2000 }
);
session.on('error', function (err) { msg._walker = 'cpu'; node.error(err.message, msg); session.close(); });
const nodeRef = node; const msgRef = msg;

function walkSubtree(target) {
    return new Promise((resolve) => {
        const results = [];
        session.subtree(target.oid, 50, (varbinds) => {
            varbinds.forEach(item => {
                if (item.type !== 128 && item.type !== 129 && item.type !== 130) {
                    results.push({ oid: item.oid, value: item.value });
                }
            });
        }, (error) => {
            resolve({ error: (error && !error.message.includes('No such name')) ? error : null, data: results, target: target });
        });
    });
}

(async () => {
    let responses = await Promise.all(targetOIDs.map(t => walkSubtree(t)));
    let cpuResult = null;

    for (let res of responses) {
        if (res.error || res.data.length === 0) continue;

        if (res.target.type === 'server') {
            let serverCpus = [];
            res.data.forEach(item => {
                let val = Number(item.value);
                if (!isNaN(val) && val > 0) serverCpus.push(val);
            });
            if (serverCpus.length > 0) {
                let cores = serverCpus.length;
                let totalLoad = serverCpus.reduce((sum, val) => sum + val, 0);
                cpuResult = { cores: cores, load: parseFloat((totalLoad / cores).toFixed(2)) };
            }
        }
        else if (res.target.type === 'juniper') {
            let descMap = {};
            let cpuMap = {};
            res.data.forEach(item => {
                let oidStr = Array.isArray(item.oid) ? item.oid.join('.') : String(item.oid);
                let val = (Buffer.isBuffer(item.value)) ? item.value.toString('utf8') : item.value;
                let matchDesc = oidStr.match(/1\.3\.6\.1\.4\.1\.2636\.3\.1\.13\.1\.5\.(.*)/);
                if (matchDesc) descMap[matchDesc[1]] = val;
                let matchCpu = oidStr.match(/1\.3\.6\.1\.4\.1\.2636\.3\.1\.13\.1\.8\.(.*)/);
                if (matchCpu) cpuMap[matchCpu[1]] = Number(val);
            });
            let reCpus = [];
            Object.keys(descMap).forEach(idx => {
                if (String(descMap[idx]).toLowerCase().includes('routing engine')) {
                    if (cpuMap[idx] !== undefined && cpuMap[idx] > 0) {
                        reCpus.push(cpuMap[idx]);
                    }
                }
            });
            if (reCpus.length > 0) {
                let totalLoad = reCpus.reduce((a,b)=>a+b, 0);
                let avgLoad = parseFloat((totalLoad / reCpus.length).toFixed(2));
                if (!cpuResult) {
                    cpuResult = { cores: reCpus.length, load: avgLoad };
                } else {
                    cpuResult.load = avgLoad;
                }
            }
        }
    }

    session.close();
    msgRef.payload = { cpu: cpuResult };
    nodeRef.send(msgRef);
})();
return null;

const snmp = global.get('snmp');
if (!snmp) { msg.payload = { disk: null }; return msg; }

const targetOIDs = [
    { oid: '1.3.6.1.2.1.25.2.3.1', type: 'server' },
    { oid: '1.3.6.1.4.1.2636.3.1.13.1', type: 'juniper' }
];

const session = snmp.createSession(
    msg.host, msg.community || env.get('SNMP_COMMUNITY') || 'public',
    { port: msg.snmp_port || 161, version: snmp.Version2c, retries: 1, timeout: 2000 }
);
session.on('error', function (err) { msg._walker = 'storage'; node.error(err.message, msg); session.close(); });
const nodeRef = node; const msgRef = msg;

function walkSubtree(target) {
    return new Promise((resolve) => {
        const results = [];
        session.subtree(target.oid, 50, (varbinds) => {
            varbinds.forEach(item => results.push(item));
        }, (error) => {
            resolve({ error: (error && !error.message.includes('No such name')) ? error : null, data: results, target: target });
        });
    });
}

(async () => {
    let responses = await Promise.all(targetOIDs.map(t => walkSubtree(t)));
    let result = null;

    for (let res of responses) {
        if (res.error || res.data.length === 0) continue;

        if (res.target.type === 'server') {
            let r = { ramTotal: 0, ramUsed: 0, ramFree: 0, diskTotal: 0, diskUsed: 0, diskFree: 0, desc: {} };
            const storageTemp = {};
            let hasData = false;
            res.data.forEach(item => {
                if (item.type !== 129) {
                    let oidStr = Array.isArray(item.oid) ? item.oid.join('.') : String(item.oid);
                    let suffix = oidStr.replace(res.target.oid + '.', '');
                    let parts = suffix.split('.');
                    let prop = parts[0]; let index = parts[1];
                    if (!storageTemp[index]) storageTemp[index] = { index: index };
                    let val = (Buffer.isBuffer(item.value)) ? item.value.toString('utf8') : item.value;
                    if (prop === '2') storageTemp[index].type_oid = val;
                    if (prop === '3') storageTemp[index].name = val;
                    if (prop === '4') storageTemp[index].unit = parseInt(val);
                    if (prop === '5') storageTemp[index].size = parseInt(val);
                    if (prop === '6') storageTemp[index].used = parseInt(val);
                }
            });
            let seenSigs = new Set();
            Object.values(storageTemp).forEach(device => {
                if (!device.name || device.size == null) return;
                let sig = device.size + '_' + device.used;
                if (seenSigs.has(sig)) return; // Deduplicate by size+used signature to ignore bind mounts and jails
                seenSigs.add(sig);
                hasData = true;
                let isRam = String(device.type_oid).includes('1.3.6.1.2.1.25.2.1.2') || String(device.type_oid).includes('1.3.6.1.2.1.25.2.1.3');
                let sizeFixed = device.size < 0 ? device.size + 4294967296 : device.size;
                let totalBytes = (sizeFixed * (device.unit || 1));
                let usedFixed = device.used < 0 ? device.used + 4294967296 : device.used;
                let usedBytes = (usedFixed * (device.unit || 1));
                if (isRam) {
                    r.ramTotal += totalBytes / (1024 * 1024);
                    r.ramUsed += usedBytes / (1024 * 1024);
                } else {
                    r.diskTotal += totalBytes / (1024 * 1024 * 1024);
                    r.diskUsed += usedBytes / (1024 * 1024 * 1024);
                    let gb = totalBytes / (1024 * 1024 * 1024);
                    r.desc[device.name] = parseFloat(gb.toFixed(2));
                }
            });
            if (hasData) {
                r.ramTotal = parseFloat(r.ramTotal.toFixed(2));
                r.ramUsed = parseFloat(r.ramUsed.toFixed(2));
                r.ramFree = parseFloat((r.ramTotal - r.ramUsed).toFixed(2));
                r.diskTotal = parseFloat(r.diskTotal.toFixed(2));
                r.diskUsed = parseFloat(r.diskUsed.toFixed(2));
                r.diskFree = parseFloat((r.diskTotal - r.diskUsed).toFixed(2));
                result = r;
            }
        }
        else if (res.target.type === 'juniper') {
            let descMap = {};
            let bufferMap = {};
            res.data.forEach(item => {
                let oidStr = Array.isArray(item.oid) ? item.oid.join('.') : String(item.oid);
                let val = (Buffer.isBuffer(item.value)) ? item.value.toString('utf8') : item.value;
                let matchDesc = oidStr.match(/1\.3\.6\.1\.4\.1\.2636\.3\.1\.13\.1\.5\.(.*)/);
                if (matchDesc) descMap[matchDesc[1]] = val;
                let matchBuffer = oidStr.match(/1\.3\.6\.1\.4\.1\.2636\.3\.1\.13\.1\.11\.(.*)/);
                if (matchBuffer) bufferMap[matchBuffer[1]] = Number(val);
            });
            let reBuffers = [];
            Object.keys(descMap).forEach(idx => {
                if (String(descMap[idx]).toLowerCase().includes('routing engine')) {
                    if (bufferMap[idx] !== undefined && bufferMap[idx] > 0) {
                        reBuffers.push(bufferMap[idx]);
                    }
                }
            });
            if (reBuffers.length > 0) {
                let avgPercent = reBuffers.reduce((a,b)=>a+b, 0) / reBuffers.length;
                if (!result) result = { ramTotal: 0, ramUsed: 0, ramFree: 0, diskTotal: 0, diskUsed: 0, diskFree: 0, desc: {} };
                result.ramTotal = 100;
                result.ramUsed = parseFloat(avgPercent.toFixed(2));
                result.ramFree = parseFloat((100 - avgPercent).toFixed(2));
            }
        }
    }

    session.close();
    msgRef.payload = { disk: result };
    nodeRef.send(msgRef);
})();
return null;

// ====================================================================
// ⚠️ [รอการตรวจสอบ] การอัปเกรด 64-Bit Network Counters (รองรับ 10Gbps+)
// ====================================================================
// สาเหตุ: OID 1.3.6.1.2.1.2.2.1 เป็นแบบ 32-bit ซึ่งจะนับได้สูงสุดแค่ 4.29 GB 
// ถ้ามอนิเตอร์พอร์ต 10Gbps ค่าแบนด์วิดท์จะเกินและตีกลับทุกๆ 3.4 วินาที ทำให้การคำนวณผิดพลาด
// 
// วิธีแก้: หากต้องการอัปเกรดให้รองรับพอร์ตความเร็วสูง ให้บอกผมว่า "อัปเกรด 64-bit เลย"
// ผมจะทำการเพิ่ม OID 1.3.6.1.2.1.31.1.1.1 (ifXTable) 
// และเปลี่ยนสมการด้านล่างให้คำนวณแบบ 64-bit Wrap Around ให้อัตโนมัติครับ
// ====================================================================

const snmp = global.get('snmp');
if (!snmp) { msg.payload = { interfaces: [] }; return msg; }

const ENABLE_FILTER = true; // เปลี่ยนเป็น false เพื่อปิดการกรอง (เอาทุก Interface)

const targetOIDs = [
    { oid: '1.3.6.1.2.1.2.2.1', type: 'standard' }
    // เพิ่ม device ใหม่ได้เลย เช่น { oid: 'x.x.x.x', type: 'cisco' }
];

const session = snmp.createSession(
    msg.host, msg.community || env.get('SNMP_COMMUNITY') || 'public',
    { port: msg.snmp_port || 161, version: snmp.Version2c, retries: 3, timeout: 5000 }
);
session.on('error', function (err) { msg._walker = 'network'; node.error(err.message, msg); session.close(); });
const nodeRef = node; const msgRef = msg; const now = Date.now();

function walkSubtree(target) {
    return new Promise((resolve) => {
        const results = [];
        session.subtree(target.oid, 50, (varbinds) => {
            varbinds.forEach(item => results.push(item));
        }, (error) => {
            resolve({ error: (error && !error.message.includes('No such name')) ? error : null, data: results, target: target });
        });
    });
}

(async () => {
    let responses = await Promise.all(targetOIDs.map(t => walkSubtree(t)));
    let interfaces = [];
    let prevNet = global.get('net_' + msgRef.host) || {};
    let max32 = BigInt("4294967295");

    for (let res of responses) {
        if (res.error || res.data.length === 0) continue;

        if (res.target.type === 'standard') {
            const netTemp = {};
            res.data.forEach(item => {
                if (item.type !== 129 && item.type !== 128) {
                    let oidStr = Array.isArray(item.oid) ? item.oid.join('.') : String(item.oid);
                    let parts = oidStr.replace(res.target.oid + '.', '').split('.');
                    let prop = parts[0]; let index = parts[1];
                    if (!netTemp[index]) netTemp[index] = { index: index };
                    let val = item.value;
                    if (prop === '2') netTemp[index].name = Buffer.isBuffer(val) ? val.toString('utf8') : String(val);
                    if (prop === '8') netTemp[index].status = Number(val);
                    if (prop === '10') netTemp[index].inBytes = BigInt(val);
                    if (prop === '16') netTemp[index].outBytes = BigInt(val);
                    if (prop === '5') netTemp[index].speed = Number(val);
                    if (prop === '6') {
                        if (Buffer.isBuffer(val)) {
                            let hex = val.toString('hex');
                            netTemp[index].mac = hex.match(/.{1,2}/g) ? hex.match(/.{1,2}/g).join(':').toUpperCase() : "Unknown";
                        }
                    }
                }
            });

            Object.values(netTemp).forEach(interf => {
                if (!interf.name) return;
                let nameStr = String(interf.name).toLowerCase();
                let isUp = (interf.status === 1);
                let isTargetName = nameStr.startsWith("ge-") || nameStr.startsWith("xe-") || nameStr.startsWith("et-") || nameStr.startsWith("ae-") || nameStr.startsWith("eth") || nameStr.startsWith("en") || nameStr.startsWith("wl");
                if (!ENABLE_FILTER || (isTargetName && isUp)) {
                    // if passed filter or filter is disabled
                    if (true) {
                        let rxMbps = 0; let txMbps = 0;
                        let inBytes = interf.inBytes || 0n; let outBytes = interf.outBytes || 0n;
                        if (prevNet[interf.index]) {
                            let prev = prevNet[interf.index];
                            let timeDiff = (now - prev.time) / 1000;
                            if (timeDiff > 0) {
                                let prevIn = BigInt(prev.inBytes || "0");
                                let prevOut = BigInt(prev.outBytes || "0");
                                let rxDiff = Number(inBytes - prevIn);
                                let txDiff = Number(outBytes - prevOut);
                                if (rxDiff < 0) rxDiff = Number((max32 - prevIn) + inBytes);
                                if (txDiff < 0) txDiff = Number((max32 - prevOut) + outBytes);
                                if (rxDiff < 0) rxDiff = 0;
                                if (txDiff < 0) txDiff = 0;
                                rxMbps = (rxDiff * 8) / (1000000 * timeDiff);
                                txMbps = (txDiff * 8) / (1000000 * timeDiff);
                            }
                        }
                        prevNet[interf.index] = { time: now, inBytes: inBytes.toString(), outBytes: outBytes.toString() };
                        interfaces.push({
                            name: interf.name, status: isUp ? "ON" : "OFF",
                            received_MB: parseFloat(rxMbps.toFixed(4)), sent_MB: parseFloat(txMbps.toFixed(4)),
                            speed_Mbps: interf.speed || 0, mac_address: interf.mac || "Unknown"
                        });
                    }
                }
            });
            break;
        }
        // else if (res.target.type === 'cisco') { ... }
    }

    session.close();
    const GC_TIMEOUT = 20 * 60 * 1000;
    Object.keys(prevNet).forEach(key => { if (now - prevNet[key].time > GC_TIMEOUT) delete prevNet[key]; });
    global.set('net_' + msgRef.host, prevNet);
    msgRef.payload = { interfaces: interfaces };
    nodeRef.send(msgRef);
})();
return null;

const snmp = global.get('snmp');
if (!snmp) { msg.payload = { temp: null }; return msg; }

const targetOIDs = [
    { oid: '1.3.6.1.4.1.2021.13.16.2.1.7', type: 'server' },
    { oid: '1.3.6.1.4.1.2636.3.1.13.1.7', type: 'juniper' }
    // เพิ่ม device ใหม่ได้เลย เช่น { oid: 'x.x.x.x', type: 'cisco' }
];

const session = snmp.createSession(
    msg.host, msg.community || env.get('SNMP_COMMUNITY') || 'public',
    { port: msg.snmp_port || 161, version: snmp.Version2c, retries: 1, timeout: 2000 }
);
session.on('error', function (err) { msg._walker = 'temp'; node.error(err.message, msg); session.close(); });
const nodeRef = node; const msgRef = msg;

function walkSubtree(target) {
    return new Promise((resolve) => {
        const results = [];
        session.subtree(target.oid, 50, (varbinds) => {
            varbinds.forEach(item => {
                if (item.type !== 128 && item.type !== 129 && item.type !== 130) {
                    let val = Buffer.isBuffer(item.value) ? item.value.toString('utf8') : item.value;
                    let num = Number(val);
                    if (!isNaN(num) && num > 0) results.push(num);
                }
            });
        }, (error) => {
            resolve({ error: (error && !error.message.includes('No such name')) ? error : null, data: results, target: target });
        });
    });
}

(async () => {
    let responses = await Promise.all(targetOIDs.map(t => walkSubtree(t)));
    let finalTemp = null;

    for (let res of responses) {
        if (res.error || res.data.length === 0) continue;

        if (res.target.type === 'server') {
            let maxTemp = Math.max(...res.data);
            if (maxTemp > 100 && maxTemp < 1000) maxTemp = maxTemp / 10;
            else if (maxTemp >= 1000) maxTemp = maxTemp / 1000;
            finalTemp = parseFloat(maxTemp.toFixed(2));
            break;
        }
        else if (res.target.type === 'juniper') {
            let maxTemp = Math.max(...res.data);
            if (maxTemp > 100 && maxTemp < 1000) maxTemp = maxTemp / 10;
            else if (maxTemp >= 1000) maxTemp = maxTemp / 1000;
            finalTemp = parseFloat(maxTemp.toFixed(2));
            break;
        }
        // else if (res.target.type === 'cisco') { ... }
    }

    session.close();
    msgRef.payload = { temp: finalTemp };
    nodeRef.send(msgRef);
})();
return null;

// Walker Error: ส่ง payload ว่างแต่ยังส่ง parts ต่อให้ Barrier นับได้
if (!msg.parts) {
    // ถ้าไม่มี parts (error จาก node ที่ไม่ได้ส่ง parts มา) ให้สร้างขึ้นมา
    msg.parts = { id: msg._msgid || 'unknown', index: 0, count: 5 };
}
msg.payload = {};
msg._walkerError = true;
return msg;

const snmp = global.get('snmp');
if (!snmp) { msg.payload = { ldi: null }; return msg; }

const targetOIDs = [
    {
        type: 'standard_ldi',
        oids: [
            '1.3.6.1.4.1.9999.1.1.0', '1.3.6.1.4.1.9999.1.2.0', '1.3.6.1.4.1.9999.1.3.0', '1.3.6.1.4.1.9999.1.4.2',
            '1.3.6.1.4.1.9999.1.4.5', '1.3.6.1.4.1.9999.1.5.1', '1.3.6.1.4.1.9999.1.6.1', '1.3.6.1.4.1.9999.1.7.1',
            '1.3.6.1.4.1.9999.2.1.0', '1.3.6.1.4.1.9999.2.2.0'
        ]
    }
    // เพิ่ม device ใหม่ได้เลย เช่น { type: 'sensor_v2', oids: ['x.x.x.x', ...] }
];

const session = snmp.createSession(
    msg.host, msg.community || env.get('SNMP_COMMUNITY') || 'public',
    { port: msg.snmp_port || 161, version: snmp.Version2c, retries: 1, timeout: 2000 }
);
session.on('error', function (err) { msg._walker = 'ldi'; node.error(err.message, msg); session.close(); });
const nodeRef = node; const msgRef = msg;

function getOIDs(target) {
    return new Promise((resolve) => {
        session.get(target.oids, (error, varbinds) => {
            resolve({ error: (error && !error.message.includes('No such name')) ? error : null, data: varbinds || [], target: target });
        });
    });
}

(async () => {
    let responses = await Promise.all(targetOIDs.map(t => getOIDs(t)));
    let finalLdi = null;

    for (let res of responses) {
        if (res.error || res.data.length === 0) continue;

        if (res.target.type === 'standard_ldi') {
            let ldi = { throughput: 0, temperature: 0, humidity: 0, pressure: 0, joule_effect: 0, power_watt: 0, vibration: 0, wifi_rssi: 0, wifi_snr: 0 };
            let hasData = false;
            res.data.forEach(item => {
                if (item.type !== 128 && item.type !== 129 && item.type !== 130) {
                    hasData = true;
                    let oidString = Array.isArray(item.oid) ? item.oid.join('.') : String(item.oid);
                    let val = Buffer.isBuffer(item.value) ? item.value.toString('utf8') : item.value;
                    val = Number(val);
                    if (oidString.endsWith('.9999.1.1.0')) ldi.throughput = val;
                    if (oidString.endsWith('.9999.1.2.0')) ldi.temperature = val;
                    if (oidString.endsWith('.9999.1.3.0')) ldi.humidity = val;
                    if (oidString.endsWith('.9999.1.4.2')) ldi.pressure = val;
                    if (oidString.endsWith('.9999.1.4.5')) ldi.joule_effect = val;
                    if (oidString.endsWith('.9999.1.5.1')) ldi.power_watt = val;
                    if (oidString.endsWith('.9999.1.6.1')) ldi.vibration = val;
                    if (oidString.endsWith('.9999.2.1.0')) ldi.wifi_rssi = val;
                    if (oidString.endsWith('.9999.2.2.0')) ldi.wifi_snr = val;
                }
            });
            if (hasData) { finalLdi = ldi; break; }
        }
        // else if (res.target.type === 'sensor_v2') { ... }
    }

    session.close();
    msgRef.payload = { ldi: finalLdi };
    nodeRef.send(msgRef);
})();
return null;

const pool = global.get('pgPool');
if (!pool) { node.error('pgPool not available in global context'); return null; }

const sql = 'SELECT device_id AS machine_id, hostname, ip_address, snmp_community AS community, snmp_port, device_type FROM public.devices WHERE enabled = true';

pool.query(sql, [], function(err, result) {
    if (err) { node.warn('Device Registry: ' + err.message + ' — using fallback defaults'); return; }

    const registry = {};
    if (result && result.rows) {
        result.rows.forEach(row => {
            registry[row.machine_id] = {
                hostname: row.hostname || row.machine_id,
                ip_address: row.ip_address || row.hostname,
                community: row.community,
                snmp_port: row.snmp_port || 161,
                device_type: row.device_type || 'server'
            };
        });
    }

    // REPLACE completely instead of Object.assign to remove disabled/deleted devices
    global.set('deviceRegistry', registry);

    // FIX MEMORY LEAK: Sweep old net_ global objects
    const globalKeys = global.keys();
    const activeIps = Object.values(registry).map(d => d.ip_address);
    globalKeys.forEach(k => {
        if (k.startsWith('net_')) {
            const ip = k.replace('net_', '');
            if (!activeIps.includes(ip)) {
                global.set(k, undefined); // Remove from memory
                // node.warn('Garbage collected offline device net cache: ' + ip);
            }
        }
    });
    //node.warn('Loaded Devices: ' + JSON.stringify(registry, null, 2));
    //node.log('Device registry loaded: ' + Object.keys(registry).length + ' devices');
});
return null;

// ป้องกันความผิดพลาดดรอปข้อความทิ้งถ้าไม่มี IP
if (!msg.host) {
    node.error("Missing host configuration for machine: " + (msg.machine_id || "Unknown"));
    return null;
}
return msg;

try {
    if (!msg.payload || typeof msg.payload !== 'object') return null;
    const deviceId = String(msg.topic || msg.machine_id || '').replace(/'/g, "''").trim();
    if (!deviceId) return null;

    const walkerType = msg._walker || 'unknown';
    const isOffline = walkerType === 'offline';
    const parsed = (Array.isArray(msg.payload)) ? Object.assign({}, ...msg.payload) : msg.payload;
    const currentTime = new Date().toISOString();

    // ZONE 1: STATEFUL FORMATTING (จัดฟอร์แมตและจดจำสถานะล่าสุดของอุปกรณ์)
    const stateKey = 'dev_state_' + deviceId;
    let state = flow.get(stateKey) || {
        cpu_cores: null, 
        cpu_load: null,
        ram_total: null, 
        ram_used: null, 
        ram_free: null,
        disk_total: null, 
        disk_used: null, 
        disk_free: null, 
        disk_desc: '{}',
        temp: null,
        ifaces: [],
        ldi: { throughput: 0, temperature: 0, humidity: 0, pressure: 0, joule_effect: 0, power_watt: 0, vibration: 0, wifi_rssi: 0, wifi_snr: 0 }
    };

    if (isOffline) {
        state.cpu_cores = 0; 
        state.cpu_load = 0;
        state.ram_total = 0; 
        state.ram_used = 0; 
        state.ram_free = 0;
        state.disk_total = 0; 
        state.disk_used = 0; 
        state.disk_free = 0; 
        state.disk_desc = '{}';
        state.temp = 0;
        state.ifaces = state.ifaces.map(i => ({ ...i, rx_mbps: 0, tx_mbps: 0, status: 'DOWN' }));
        state.ldi = { throughput: 0, temperature: 0, humidity: 0, pressure: 0, joule_effect: 0, power_watt: 0, vibration: 0, wifi_rssi: 0, wifi_snr: 0 };
    } else {
        if (parsed.cpu) { state.cpu_cores = parsed.cpu.cores; state.cpu_load = isNaN(parsed.cpu.load) ? 0 : parsed.cpu.load; }
        if (parsed.disk) {
            state.ram_total = parsed.disk.ramTotal; 
            state.ram_used = parsed.disk.ramUsed; 
            state.ram_free = parsed.disk.ramFree;
            state.disk_total = parsed.disk.diskTotal; 
            state.disk_used = parsed.disk.diskUsed; 
            state.disk_free = parsed.disk.diskFree;
            state.disk_desc = JSON.stringify(parsed.disk.desc || {});
        }
        if (parsed.temp !== undefined && parsed.temp !== null) { state.temp = isNaN(parsed.temp) ? null : parsed.temp; }
        if (parsed.interfaces && Array.isArray(parsed.interfaces)) {
            state.ifaces = parsed.interfaces.map(i => ({
                name: i.name, rx_mbps: i.received_MB || 0, tx_mbps: i.sent_MB || 0,
                rx_errors: 0, tx_errors: 0, rx_drops: 0, tx_drops: 0, status: i.status === 'ON' ? 'UP' : 'DOWN'
            }));
        }
        if (parsed.ldi) {
            state.ldi = {
                throughput: parsed.ldi.throughput || 0, 
                temperature: parsed.ldi.temperature || 0, 
                humidity: parsed.ldi.humidity || 0,
                pressure: parsed.ldi.pressure || 0, 
                joule_effect: parsed.ldi.joule_effect || 0, 
                power_watt: parsed.ldi.power_watt || 0,
                vibration: parsed.ldi.vibration || 0, 
                wifi_rssi: parsed.ldi.wifi_rssi || 0, 
                wifi_snr: parsed.ldi.wifi_snr || 0
            };
        }
    }
    flow.set(stateKey, state);

    // ZONE 2: PER-DEVICE BUFFER MANAGEMENT (นำข้อมูลเข้าคิวและป้องกัน OOM)
    const BATCH_INTERVAL_SEC = 10;
    const BUFFER_MAX = 200;
    const now = Date.now();
    const bufKey = 'batch_buf_' + deviceId;
    let buffer = flow.get(bufKey) || { sys: [], net: [], ldi: [], lastFlush: now };

    function enforceBufferLimit(buf, type) {
        if (buf.length >= BUFFER_MAX) {
            buf.shift();
            node.warn(`BUFFER OVERFLOW: Dropped oldest ${type} metric for ${deviceId} to prevent OOM.`);
        }
    }

    const hasSys = isOffline || parsed.cpu !== undefined || parsed.disk !== undefined || parsed.temp !== undefined;
    const hasNet = isOffline || parsed.interfaces !== undefined;
    const hasLdi = isOffline || parsed.ldi !== undefined;

    if (hasSys) {
        enforceBufferLimit(buffer.sys, 'sys');
        buffer.sys.push({ time: currentTime, device_id: deviceId, cpu_cores: state.cpu_cores, cpu_load_percent: state.cpu_load, ram_total_mb: state.ram_total, ram_used_mb: state.ram_used, ram_free_mb: state.ram_free, disk_total_gb: state.disk_total, disk_used_gb: state.disk_used, disk_free_gb: state.disk_free, disk_description: state.disk_desc, temp_c: state.temp });
    }
    if (hasNet) {
        state.ifaces.forEach(iface => {
            enforceBufferLimit(buffer.net, 'net');
            buffer.net.push({ time: currentTime, device_id: deviceId, iface_name: iface.name, rx_mbps: iface.rx_mbps, tx_mbps: iface.tx_mbps, rx_errors: iface.rx_errors, tx_errors: iface.tx_errors, rx_drops: iface.rx_drops, tx_drops: iface.tx_drops, status: iface.status });
        });
    }
    if (hasLdi) {
        enforceBufferLimit(buffer.ldi, 'ldi');
        buffer.ldi.push({ time: currentTime, device_id: deviceId, ...state.ldi });
    }

    // ZONE 3: DATABASE BATCH FLUSH (เคลียร์คิวลง Database ทุกๆ 10 วินาที)
    const elapsedSec = (now - buffer.lastFlush) / 1000;
    if (elapsedSec >= BATCH_INTERVAL_SEC) {
        const pool = global.get('pgPool');
        if (pool) {
            const queries = buildBatchQueries(buffer.sys, buffer.net, buffer.ldi);
            for (const q of queries) {
                pool.query(q.sql, q.params, function(err) {
                    if (err) node.error(`Batch INSERT [${q.name}] failed for ${deviceId}: ${err.message}`);
                });
            }
        } else {
            node.error('pgPool missing in global context!');
        }
        flow.set(bufKey, { sys: [], net: [], ldi: [], lastFlush: now });
    } else {
        flow.set(bufKey, buffer);
    }
    return null;

} catch (err) {
    node.error('Unified Parser Error: ' + err.message, msg);
    return null;
}

// ── SQL Query Builder Helper ──
function buildBatchQueries(sysRows, netRows, ldiRows) {
    sysRows = Array.isArray(sysRows) ? sysRows : []; netRows = Array.isArray(netRows) ? netRows : []; ldiRows = Array.isArray(ldiRows) ? ldiRows : [];
    const queries = [];
    if (sysRows.length > 0) {
        const ph = sysRows.map((_, i) => { const b = i * 11; return "(NOW(),$" + (b+1) + ",$" + (b+2) + ",$" + (b+3) + ",$" + (b+4) + ",$" + (b+5) + ",$" + (b+6) + ",$" + (b+7) + ",$" + (b+8) + ",$" + (b+9) + ",$" + (b+10) + "::jsonb,$" + (b+11) + ")"; }).join(',');
        const params = [];
        for (const r of sysRows) { params.push(r.device_id, r.cpu_cores, r.cpu_load_percent, r.ram_total_mb, r.ram_used_mb, r.ram_free_mb, r.disk_total_gb, r.disk_used_gb, r.disk_free_gb, r.disk_description, r.temp_c); }
        queries.push({ name: 'sys', sql: 'INSERT INTO public.sys_metrics ("time",device_id,cpu_cores,cpu_load_percent,ram_total_mb,ram_used_mb,ram_free_mb,disk_total_gb,disk_used_gb,disk_free_gb,disk_description,temp_c) VALUES ' + ph, params: params });
    }
    if (netRows.length > 0) {
        const ph = netRows.map((_, i) => { const b = i * 9; return "(NOW(),$" + (b+1) + ",$" + (b+2) + ",$" + (b+3) + ",$" + (b+4) + ",$" + (b+5) + ",$" + (b+6) + ",$" + (b+7) + ",$" + (b+8) + ",$" + (b+9) + ")"; }).join(',');
        const params = [];
        for (const r of netRows) { params.push(r.device_id, r.iface_name, r.rx_mbps, r.tx_mbps, r.rx_errors, r.tx_errors, r.rx_drops, r.tx_drops, r.status); }
        queries.push({ name: 'net', sql: 'INSERT INTO public.net_metrics ("time",device_id,iface_name,rx_mbps,tx_mbps,rx_errors,tx_errors,rx_drops,tx_drops,status) VALUES ' + ph, params: params });
    }
    if (ldiRows.length > 0) {
        const ph = ldiRows.map((_, i) => { const b = i * 10; return "(NOW(),$" + (b+1) + ",$" + (b+2) + ",$" + (b+3) + ",$" + (b+4) + ",$" + (b+5) + ",$" + (b+6) + ",$" + (b+7) + ",$" + (b+8) + ",$" + (b+9) + ",$" + (b+10) + ")"; }).join(',');
        const params = [];
        for (const r of ldiRows) { params.push(r.device_id, r.throughput, r.temperature, r.humidity, r.pressure, r.joule_effect, r.power_watt, r.vibration, r.wifi_rssi, r.wifi_snr); }
        queries.push({ name: 'ldi', sql: 'INSERT INTO public.ldi_metrics ("time",device_id,throughput,temperature,humidity,pressure,joule_effect,power_watt,vibration,wifi_rssi,wifi_snr) VALUES ' + ph, params: params });
    }
    return queries;
}

const registry = global.get('deviceRegistry') || {};
const devices = Object.keys(registry).map(id => {
    return {
        machine_id: id,
        topic: id,
        host: registry[id].ip_address || registry[id].hostname,
        community: registry[id].community,
        snmp_port: registry[id].snmp_port,
        device_type: registry[id].device_type || 'server'
    };
});
if (devices.length === 0) return null;

const targetDurationMs = 8000;
const tickMs = 25;
const ticks = targetDurationMs/tickMs;
const batchSize = Math.max(1, Math.ceil(devices.length / ticks));

let i = 0;
const interval = setInterval(() => {
    let sent = 0;
    while(sent < batchSize && i < devices.length) {
        node.send(devices[i]);
        i++;
        sent++;
    }
    if (i >= devices.length) {
        clearInterval(interval);
    }
}, tickMs);
return null;

msg.topic = msg.payload.machine_id;
msg.payload = msg.payload.metrics;
return msg;

const mid = msg.machine_id || msg.topic || 'Unknown Device';
const errorMsg = (msg.error && msg.error.message) ? msg.error.message : 'Timeout or Disconnected';

// ประเมินความเสี่ยงและระบุชื่อเซ็นเซอร์
let sensor = "Unknown Sensor";
let risk = "Low";

switch(msg._walker) {
    case 'cpu': 
        sensor = "CPU"; 
        risk = "Medium"; 
        break;
    case 'storage': 
        sensor = "Storage/RAM"; 
        risk = "High"; 
        break;
    case 'network': 
        sensor = "Network Interface"; 
        risk = "Critical"; 
        break;
    case 'temp': 
        sensor = "Temperature"; 
        risk = "Critical"; 
        break;
    case 'ldi': 
        sensor = "LDI Environment"; 
        risk = "Medium"; 
        break;
    default:
        sensor = "General System";
        risk = "Warning";
}

// จัดการเวลาให้เป็นเวลาไทย (UTC+7) และอ่านง่าย
const tzOffset = 7 * 60 * 60 * 1000;
const localTime = new Date(Date.now() + tzOffset)
    .toISOString()
    .replace(/T/, ' ')
    .replace(/\..+/, '');

// จัด Format ข้อความส่งเข้า Line/Telegram
msg.payload = ` [IMS ALERT - ${sensor} Error]\n Risk Level: ${risk}\n Device: ${mid}\n Detail: ${errorMsg}\n Time: ${localTime}`;

return msg;

const os = global.get('os');
const msgs = [];
const communityString = msg.community || env.get('SNMP_COMMUNITY') || 'public';
const communities = communityString.split(',').map(c => c.trim());
let subnetsToScan = [];

if (msg.subnet && msg.subnet !== 'AUTO') {
    subnetsToScan.push(msg.subnet);
} else {
    const envSubnets = env.get('DISCOVERY_SUBNETS');
    if (envSubnets) {
        subnetsToScan = envSubnets.split(',').map(s => s.trim());
    } else {
        const nets = os.networkInterfaces();
        for (const name of Object.keys(nets)) {
            for (const net of nets[name]) {
                // Ignore docker default bridge networks and localhost
                if (net.family === 'IPv4' && !net.internal && !net.address.startsWith('172.')) {
                    const parts = net.address.split('.');
                    parts.pop();
                    subnetsToScan.push(parts.join('.') + '.');
                }
            }
        }
        if (subnetsToScan.length === 0) {
            node.error("FAIL LOUD: No physical interfaces found and DISCOVERY_SUBNETS not set. Aborting discovery.");
            return null;
        }
    }
}

for (const subnet of subnetsToScan) {
    let prefix = subnet.endsWith('.') ? subnet : subnet + '.';
    for (let i = 1; i <= 254; i++) {
        let targetIp = prefix + i;
        for (const comm of communities) {
            msgs.push({ ip: targetIp, community: comm });
        }
    }
}

node.warn("Generated " + msgs.length + " IPs for discovery.");
return [msgs];

const snmp = global.get('snmp');
if (!snmp) return null;

// ดึง Community (ถ้าไม่มีใช้ public)
const community = msg.community || env.get('SNMP_COMMUNITY') || 'public';
msg.community = community;

//สร้างการเชื่อมต่อ SNMP
const session = snmp.createSession(msg.ip, community, { 
    port: 161, 
    version: snmp.Version2c, 
    retries: 0, 
    timeout: 300 
});

//ยิงขอข้อมูล sysName (OID: 1.3.6.1.2.1.1.5.0)
session.on('error', function(err) { session.close(); });

session.get(['1.3.6.1.2.1.1.5.0'], function (error, varbinds) {
    if (!error) {
        // ถ้าไม่มี Error แสดงว่าเครื่องนี้มีอยู่จริง
        if (varbinds.length > 0 && !snmp.isVarbindError(varbinds[0])) {
            let val = varbinds[0].value;
            msg.sysName = Buffer.isBuffer(val) ? val.toString('utf8') : String(val);
        } else {
            msg.sysName = "AUTO-" + msg.ip; 
        }
        // ส่งต่อให้โหนดถัดไปบันทึกลง Database
        node.send(msg);
    }
    session.close();
});

return null;

const pool = global.get('pgPool');
if (!pool) return null;

const safeName = (msg.sysName && msg.sysName.trim() !== '') ? msg.sysName.trim().replace(/\s+/g, '_') : 'AUTO';
const machineId = safeName + '_' + msg.ip.replace(/\./g, '_');
const hostname = (msg.sysName && msg.sysName.trim() !== '') ? msg.sysName.trim() : msg.ip;
const ipAddress = msg.ip;
const community = msg.community || 'public';

// ตรวจจับ device_type จาก sysName
let deviceType = 'server';
const sysNameLower = (msg.sysName || '').toLowerCase();
if (sysNameLower.includes('juniper') || sysNameLower.includes('junos') || sysNameLower.match(/^(ex|qfx|srx|mx|acx)/)) {
    deviceType = 'switch_juniper';
} else if (sysNameLower.includes('cisco') || sysNameLower.match(/^(c\d|ws-|cat)/)) {
    deviceType = 'switch_cisco';
} else if (sysNameLower.includes('huawei') || sysNameLower.includes('vrp')) {
    deviceType = 'switch_huawei';
}

const sql = `
    INSERT INTO public.devices (device_id, hostname, ip_address, snmp_community, snmp_port, device_type, enabled)
    VALUES ($1, $2, $3, $4, 161, $5, true)
    ON CONFLICT (device_id) DO UPDATE
    SET hostname = EXCLUDED.hostname,
        ip_address = EXCLUDED.ip_address,
        snmp_community = EXCLUDED.snmp_community,
        device_type = EXCLUDED.device_type
`; 

pool.query(sql, [machineId, hostname, ipAddress, community, deviceType])
    .then(result => {
        node.warn('✅ Upserted device: ' + machineId + ' (' + hostname + ') type=' + deviceType);
    })
    .catch(err => {
        node.error('Failed to register ' + hostname + ': ' + err.message);
    });

return null;

const payload = msg.payload;
if (!payload || !payload.alerts) return null;

const alerts = payload.alerts;
let msgText = '\ud83d\udd14 *IMS SYSTEM ALERT [' + (payload.status || 'unknown').toUpperCase() + ']* \ud83d\udd14\n\n';

for (let i = 0; i < alerts.length; i++) {
    const a = alerts[i];
    const labels = a.labels || {};
    const annotations = a.annotations || {};

    let icon = '\u26a0\ufe0f';
    if (labels.severity === 'critical') icon = '\ud83d\udd25';
    if (payload.status === 'resolved') icon = '\u2705';

    msgText += icon + ' *' + (labels.alertname || 'Unknown Alert') + '*\n';
    msgText += '\ud83d\udda5\ufe0f *Host:* ' + (labels.machine_id || labels.instance || 'System') + '\n';
    msgText += '\ud83d\udcdd *Detail:* ' + (annotations.summary || 'N/A') + '\n';
    if (annotations.description) msgText += '\ud83d\udca1 *Desc:* ' + annotations.description + '\n';

    const startTime = a.startsAt ? new Date(a.startsAt).toLocaleString('th-TH') : 'Unknown';
    msgText += '\ud83d\udd52 *Time:* ' + startTime + '\n';
    msgText += '-------------------\n';
}

// Truncate if too long to prevent API 400 Bad Request during major outages
if (msgText.length > 4000) {
    msgText = msgText.substring(0, 4000) + '\n\n... [TRUNCATED: Too many alerts!]';
}
msg.payload = msgText;
return msg;

const token = env.get('LINE_CHANNEL_ACCESS_TOKEN') || '';
const userId = env.get('LINE_USER_ID') || '';

if (!token || !userId) {
