return msg;

const results = msg.payload;
if (!Array.isArray(results) || results.length === 0) return null;

let val = results[0].value;
if (Buffer.isBuffer(val)) val = val.toString('utf8');

// ฝากชื่อเข้าไปflow อื่น
flow.set("myServer", val);

msg.payload = { 
    systemName: val 
    };
//console.log(msg.payload.systemName);
return msg;

// ดึงข้อมูล Payload ที่ได้จาก SNMP
let results = msg.payload;
if (!Array.isArray(results) || results.length === 0) return null;

// อาเรย์เก็บเปอร์เซ็นต์การใช้งานของ CPU แต่ละ Core
let cpuCores = [];
results.forEach(item => {
    let oid = String(item.oid);
    let val = (Buffer.isBuffer(item.value) ? item.value.toString('utf8') : item.value);

    // กรองหาเฉพาะ OID ของ CPU 
    /*if (oid.includes("1.3.6.1.4.1.2636.3.1.13.1.8.")) {
        let num = Number(val);
        if (!Number.isNaN(num) && num > 0) {
            cpuCores.push(num);
        }
    }*/
     if (oid.includes("1.3.6.1.2.1.25.3.3.1.2.")) {
        let num = Number(val);
        if (!Number.isNaN(num) && num > 0) {
            cpuCores.push(num);
        }
    }
});

if (cpuCores.length === 0) return null;

// คำนวณหาค่าเฉลี่ยของทุก Core รวมกัน
let total = cpuCores.reduce((sum, val) => sum + val, 0);
let average = total / cpuCores.length;

let used_percent = Number(average.toFixed(2));
let free_percent = Number((100 - used_percent).toFixed(2));

// ส่งโครงสร้างข้อมูลกราฟ CPU ออกไป
msg.payload = {
    type: "CPU",
    cores: cpuCores.length,
    used_percent: used_percent,
    free_percent: free_percent
};

return msg;

// ดึงข้อมูล Payload ที่ได้จาก SNMP
let results = msg.payload;
if (!Array.isArray(results) || results.length === 0) return null;

// ตัวแปรเก็บขนาด RAM รวมทั้งหมด
let totalRamMB = 0;
let components = {};

results.forEach(item => {
    if (item.value == null || !item || !item.oid) return;
    let oid = String(item.oid);
    let val = (Buffer.isBuffer(item.value) ? item.value.toString("utf8") : item.value);

    // OID .15 คือขนาดรวมของ RAM ระบบ
    if (oid.includes(".13.1.15.")) {
        let num = Number(val);
        if (!Number.isNaN(num) && num > totalRamMB) totalRamMB = num;
    }

    // แยกเอา Index ของแต่ละชิ้นส่วนเพื่อจับคู่ชื่อและค่าการใช้งาน
    let match = oid.match(/\.13\.1\.(5|11|12)\.(.+)$/);
    if (match) {
        let type = match[1];
        let idx = match[2];
        if (!components[idx]) components[idx] = { buffer: 0, heap: 0, desc: "" };

        if (type === "5") components[idx].desc = String(val).toUpperCase();
        if (type === "11") components[idx].buffer = Number(val);
        if (type === "12") components[idx].heap = Number(val);
    }
});

let utilization = 0;

for (let idx in components) {
    // เลือกเอาเฉพาะ RAM ของ ROUTING ENGINE มาใช้ (ถ้าเป็นรุ่นอื่นอาจจะต้องเปลี่ยนคำนี้)
    if (components[idx].desc.includes("ROUTING ENGINE")) {
        utilization = Math.max(components[idx].buffer || 0, components[idx].heap || 0);
        break; // Stop at the primary engine
    }
}

// Fallback: If no routing engine found, take the highest pool
if (utilization === 0) {
    let allPools = Object.values(components).map(c => Math.max(c.buffer || 0, c.heap || 0));
    if (allPools.length > 0) utilization = Math.max(...allPools);
} console.log(utilization);

if (utilization > 0) {
    let total_gb = 0;
    let used_gb = 0;
    let free_gb = 0;

    if (totalRamMB > 0) {
        total_gb = Number((totalRamMB / 1024).toFixed(2));
        used_gb = Number(((total_gb * utilization) / 100).toFixed(2));
        free_gb = Number((total_gb - used_gb).toFixed(2));
    }

    // ส่งข้อมูล RAM ออกไปแสดงผลที่กราฟ
    msg.payload = {
        type: "RAM",
        total_gb: total_gb,
        used_gb: used_gb,
        free_gb: free_gb,
        utilization: utilization
    };
    return msg;
}

return null;

// ดึงข้อมูล Payload ที่ได้จาก SNMP
let results = msg.payload;
if (!Array.isArray(results) || results.length === 0) return null;

const disks = {};

results.forEach(item => {
    let oid = String(item.oid);
    // ดึงเลข Index ประจำดิสก์
    const match = oid.match(/\.(\d+)$/);
    if (!match) return;
    const index = match[1];

    if (!disks[index]) disks[index] = { index: index };

    let val = (Buffer.isBuffer(item.value)) ? item.value.toString('utf8') : item.value;

    if (oid.includes(".25.2.3.1.3.")) disks[index].descr = val;
    if (oid.includes(".25.2.3.1.4.")) disks[index].allocUnit = Number(val);
    if (oid.includes(".25.2.3.1.5.")) disks[index].sizeBlocks = Number(val);
    if (oid.includes(".25.2.3.1.6.")) disks[index].usedBlocks = Number(val);
});

const calculatedDisks = [];

Object.entries(disks).forEach(([index, d]) => {

    if (d.descr && d.sizeBlocks > 0 && d.allocUnit > 0) {
        const descrUpper = String(d.descr).toUpperCase();

        // ข้ามพวกที่เป็น RAM หรือ Virtual Memory (เราจะเอาแค่ดิสก์เก็บข้อมูลจริงๆ)
        if (descrUpper.includes("MEMORY") || descrUpper.includes("VIRTUAL")) return;

        // คำนวณขนาดเป็น Byte และแปลงเป็น GB
        const totalBytes = d.sizeBlocks * d.allocUnit;
        const usedBytes = d.usedBlocks * d.allocUnit;

        const totalGB = (totalBytes / Math.pow(1024, 3)).toFixed(2);
        const usedGB = (usedBytes / Math.pow(1024, 3)).toFixed(2);
        const freeGB = ((totalBytes - usedBytes) / Math.pow(1024, 3)).toFixed(2);

        const utilPercent = ((d.usedBlocks / d.sizeBlocks) * 100).toFixed(1);

        // จัดโครงสร้างข้อมูลดิสก์เตรียมส่งออก
        calculatedDisks.push({
            diskIndex: index,
            name_disk: d.descr,
            total_GB: Number(totalGB),
            used_GB: Number(usedGB),
            free_GB: Number(freeGB),
            utilization_percent: Number(utilPercent)
        });
    }
});

msg.payload = calculatedDisks;
return msg;

// ดึงข้อมูล Payload ที่ได้จาก SNMP
let results = msg.payload;
if (!Array.isArray(results) || results.length === 0) return null;

// อาเรย์เก็บเปอร์เซ็นต์การใช้งานของ CPU แต่ละ Core
let cpuCores = [];
results.forEach(item => {
    let oid = String(item.oid);
    let val = (Buffer.isBuffer(item.value) ? item.value.toString('utf8') : item.value);

    // กรองหาเฉพาะ OID ของ CPU (ถ้าไม่ใช่ของ Juniper อาจจะต้องเปลี่ยนเลขนี้)
    if (oid.includes(".13.1.8.")) {
        let num = Number(val);
        if (!Number.isNaN(num) && num > 0) {
            cpuCores.push(num);
        }
    }
});

if (cpuCores.length === 0) return null;

// คำนวณหาค่าเฉลี่ยของทุก Core รวมกัน
let total = cpuCores.reduce((sum, val) => sum + val, 0);
let average = total / cpuCores.length;

let used_percent = Number(average.toFixed(2));
let free_percent = Number((100 - used_percent).toFixed(2));

// ส่งโครงสร้างข้อมูลกราฟ CPU ออกไป
msg.payload = {
    type: "CPU",
    cores: cpuCores.length,
    used_percent: used_percent,
    free_percent: free_percent
};

return msg;

let results = msg.payload;
if (!Array.isArray(results) || results.length === 0) {
    node.warn("Network node received empty payload.");
    return null;
}

const interfaces = {};

results.forEach(item => {
    if (!item || !item.oid || item.value == null) return;
    let oid = String(item.oid);
    const match = oid.match(/\.(\d+)$/);
    if (!match) return;
    const index = match[1];

    if (!interfaces[index]) interfaces[index] = { index: index };

    let val = Buffer.isBuffer(item.value) ? item.value.toString('utf8') : item.value;

    if (oid.includes("1.3.6.1.2.1.2.2.1.2.")) interfaces[index].name = val;
    if (oid.includes("1.3.6.1.2.1.2.2.1.8.")) interfaces[index].status = Number(val);
    if (oid.includes("1.3.6.1.2.1.2.2.1.10.")) interfaces[index].inBytes = BigInt(val);
    if (oid.includes("1.3.6.1.2.1.2.2.1.16.")) interfaces[index].outBytes = BigInt(val);
});

let totalPhysical = 0;
let usedPhysical = 0;
let networkData = []; // เปลี่ยนเป็น Array ตามระบบใหม่
const now = Date.now();
const host = msg.host || "old_system_host";
let prevNet = global.get('old_net_' + host) || {};
let max32 = BigInt("4294967295");

Object.values(interfaces).forEach(interf => {
    if (!interf.name) return;

    let nameStr = String(interf.name).toLowerCase();

    // เลือกเฉพาะพอร์ตสายแลนจริง (Physical Ports)
    // ถ้าอยากได้พอร์ตทั้งหมด ให้ใส่คอมเมนต์ (//) หน้าคำว่า if ด้านล่างนี้ และเอาปีกกา { } ออก
     if (nameStr.startsWith("ge-") || nameStr.startsWith("xe-") || nameStr.startsWith("et-") || nameStr.startsWith("ae-")) 
     {
        totalPhysical++;

        let isUp = (interf.status === 1);

        // เลือกเฉพาะพอร์ตที่ UP ให้ใส่คอมเมนต์ (//) หน้าคำว่า if บรรทัดด้านล่างนี้ออก (ปัจจุบันเปิดให้ดูทั้งหมด)
         if (isUp) 
         {
            if (isUp) usedPhysical++;

            let rxMbps = 0; let txMbps = 0;
            let inBytes = interf.inBytes || 0n; 
            let outBytes = interf.outBytes || 0n;

            if (prevNet[interf.index]) {
                let prev = prevNet[interf.index];
                let timeDiff = (now - prev.time) / 1000;
                if (timeDiff > 0) {
                    let prevIn = BigInt(prev.inBytes || "0");
                    let prevOut = BigInt(prev.outBytes || "0");

                    let rxDiff = Number(inBytes - prevIn);
                    let txDiff = Number(outBytes - prevOut);

                    if (rxDiff < 0) rxDiff = Number((max32 - prevIn) + inBytes);
                    if (txDiff < 0) txDiff = Number((max32 - prevOut) + outBytes);

                    if (rxDiff < 0) rxDiff = 0;
                    if (txDiff < 0) txDiff = 0;

                    rxMbps = (rxDiff * 8) / (1000000 * timeDiff);
                    txMbps = (txDiff * 8) / (1000000 * timeDiff);
                }
            }

            prevNet[interf.index] = { time: now, inBytes: inBytes.toString(), outBytes: outBytes.toString() };

            networkData.push({
                name: interf.name,
                status: isUp ? "ON" : "OFF",
                received_MB: parseFloat(rxMbps.toFixed(4)),
                sent_MB: parseFloat(txMbps.toFixed(4))
            });
         } 
     } 
});

// GC
const GC_TIMEOUT = 20 * 60 * 1000;
Object.keys(prevNet).forEach(key => {
    if (now - prevNet[key].time > GC_TIMEOUT) delete prevNet[key];
});
global.set('old_net_' + host, prevNet);

msg.summary = {
    total_physical_ports: totalPhysical,
    used_physical_ports: usedPhysical
};

//node.warn("Network Summary (Old System Upgraded): " + usedPhysical + " / " + totalPhysical + " ports are UP!");

msg.payload = networkData;
return msg;

